 WHERE meetup_id = #{meetupId}
   AND member_id = #{memberId}


    AND status IN

        #{status}

SELECT 
    (SELECT COUNT(*) 
       FROM meetups 
      WHERE member_id = #{memberId} 
        AND delete_yn = 'N' 
        AND status != 'DELETED'
     ) AS meetupCount,

    (SELECT COUNT(*) 
       FROM reviews 
      WHERE member_id = #{memberId} 
        AND delete_yn = 'N'
     ) AS reviewCount,

    (SELECT COUNT(*) 
       FROM meetup_likes   
      WHERE member_id = #{memberId}
     ) AS likeCount,

    (SELECT COUNT(*) 
       FROM meetup_applications 
      WHERE member_id = #{memberId} 
        AND status IN ('APPROVED', 'PENDING')
     ) AS applicationCount
FROM DUAL

mapper.update:
UPDATE meetup_applications
SET status = #{status},
	reject_reason = #{rejectReason, jdbcType=VARCHAR}
WHERE 1=1
AND application_id = #{applicationId}

